class Solution {
public:
    string licenseKeyFormatting(string s, int k) {
        string result;
        string temp;
        int count = 0;

        // Remove dashes and convert to uppercase
        for (char c : s) {
            if (c != '-') {
                temp += toupper(c);
            }
        }

        // Calculate the length of the first group
        int firstGroupLength = temp.length() % k;
        if (firstGroupLength == 0) {
            firstGroupLength = k;
        }

        // Add the first group to the result
        for (int i = 0; i < firstGroupLength; i++) {
            result += temp[i];
        }

        // Add the remaining groups to the result
        for (int i = firstGroupLength; i < temp.length(); i++) {
            result += temp[i];
            count++;
            if (count == k) {
                result += '-';
                count = 0;
            }
        }

        // Remove the trailing dash if exists
        if (result.back() == '-') {
            result.pop_back();
        }

        return result;
    }
};
```
